function assertP5(p5) {
  if (!p5 || p5.id !== "P5") throw new Error("id mismatch");
  if (!p5.def || !p5.desc) throw new Error("missing definition or description");
  if (!p5.applicability || !p5.applicability.predicates) throw new Error("missing applicability predicates");
  ["comps", "types", "props", "ops", "manif"].forEach((key) => {
    if (!Array.isArray(p5[key]) || p5[key].length === 0) throw new Error("missing " + key);
  });

  const findComponent = (name) => (p5.comps || []).find((c) => c.n === name);
  const findType = (name) => (p5.types || []).find((t) => t.n === name);
  const parseRecordFields = (defn) => {
    if (!defn) return new Set();
    const match = defn.trim().match(/^\((.*)\)$/);
    if (!match) return new Set();
    const fields = match[1]
      .split(",")
      .map((chunk) => chunk.trim())
      .filter(Boolean)
      .map((chunk) => (chunk.includes(":") ? chunk.split(":", 1)[0].trim() : chunk));
    return new Set(fields);
  };

  const tabs = findComponent("tabs");
  if (!tabs) throw new Error("tabs component missing");
  const opsText = (p5.ops || []).map((op) => op.def || "").join(" ");
  if ((tabs.t || "").includes("Sequence")) {
    if (opsText.includes("∪")) throw new Error("sequence tabs should not use set union");
    if (opsText.includes("\\\\")) throw new Error("sequence tabs should not use set difference");
    if (opsText.includes("tab_id ∈ tabs")) throw new Error("sequence tabs should not use set membership by id");
    if (opsText.includes("tabs[tab_id]")) throw new Error("sequence tabs should not be indexed by id");
  }

  const tabType = findType("Tab");
  if (!tabType) throw new Error("missing Tab type");
  const tabFields = parseRecordFields(tabType.def);
  if (opsText.includes("tab.item") || opsText.includes("Tab(item)")) {
    if (!tabFields.has("item")) throw new Error("Tab type must include item if ops use tab.item or Tab(item)");
  }

  const active = findComponent("active");
  if (!active) throw new Error("active component missing");
  if ((active.t || "").trim() === "ℕ") {
    if (opsText.includes("active_tab")) throw new Error("active is an index but ops reference active_tab id");
  }

  const appType = findType("ApplicabilityResult");
  if (!appType) throw new Error("ApplicabilityResult type missing");
  const typeNames = new Set((p5.types || []).map((t) => t.n));
  const appDef = appType.def || "";
  if (appDef.includes("Contraindication") && !typeNames.has("Contraindication")) {
    throw new Error("Contraindication type missing");
  }
  if (appDef.includes("Pattern") && !typeNames.has("Pattern")) {
    throw new Error("Pattern type missing");
  }

  const evalOp = (p5.ops || []).find((op) => op.n === "Evaluate Applicability");
  if (!evalOp) throw new Error("Evaluate Applicability op missing");
  if ((evalOp.def || "").includes("p.id")) {
    const predicates = (p5.applicability && p5.applicability.predicates) || {};
    Object.keys(predicates).forEach((key) => {
      if (!("id" in predicates[key])) throw new Error("predicate '" + key + "' missing id");
    });
  }

  return true;
}
